def get_geology_facts(count=3):
    """Return a random selection of Wisconsin geology facts."""
    picks = random.sample(WISCONSIN_GEOLOGY, min(count, len(WISCONSIN_GEOLOGY)))
    return [{'text': f, 'source': 'Geology'} for f in picks]


def get_maple_syrup_tips(count=2):
    """Return a random selection of maple syrup tips."""
    picks = random.sample(MAPLE_SYRUP_TIPS, min(count, len(MAPLE_SYRUP_TIPS)))
    return [{'text': t, 'source': 'Maple Syrup'} for t in picks]


def get_on_this_day(count=2):
    """Return 'On This Day' facts for today's date."""
    now = datetime.now(timezone.utc)
    key = (now.month, now.day)
    entries = ON_THIS_DAY.get(key, [])
    if not entries:
        return []
    picks = random.sample(entries, min(count, len(entries)))
    return [{'text': e, 'source': 'History'} for e in picks]
